import React, { useState, useEffect } from 'react'
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom'
import { Toaster } from 'react-hot-toast'
import { supabase } from './lib/supabaseClient'
import { Navbar } from './components/layout/Navbar'
import { Login } from './components/auth/Login'
import { Register } from './components/auth/Register'  // ADD THIS
import { Dashboard } from './components/dashboard/Dashboard'
import { CreateSession } from './components/sessions/CreateSession'
import { BrowseSessions } from './components/sessions/BrowseSessions'
import { FindPlayers } from './components/social/FindPlayers'
import { Marketplace } from './components/marketplace/Marketplace'

const PlaceholderPage: React.FC<{ title: string }> = ({ title }) => (
  <div style={{
    minHeight: '100vh',
    background: '#0a0a0a',
    color: 'white',
    padding: '40px',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center'
  }}>
    <div style={{ textAlign: 'center' }}>
      <h1 style={{ color: '#FFD700', fontSize: '32px' }}>{title}</h1>
      <p style={{ color: '#666' }}>Coming soon! 🚀</p>
    </div>
  </div>
)

function App() {
  const [user, setUser] = useState<any>(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setUser(session?.user ?? null)
      setLoading(false)
    })

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setUser(session?.user ?? null)
    })

    return () => subscription.unsubscribe()
  }, [])

  if (loading) {
    return (
      <div style={{
        minHeight: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        background: '#0a0a0a',
        color: 'white'
      }}>
        Loading...
      </div>
    )
  }

  return (
    <BrowserRouter>
      <Toaster position="top-right" toastOptions={{ style: { background: '#1a1a1a', color: '#fff' } }} />
      {user && <Navbar />}
      <Routes>
        <Route path="/login" element={!user ? <Login /> : <Navigate to="/" />} />
        <Route path="/register" element={!user ? <Register /> : <Navigate to="/" />} />  {/* ADD THIS */}
        <Route path="/" element={user ? <Dashboard /> : <Navigate to="/login" />} />
        <Route path="/create-session" element={user ? <CreateSession /> : <Navigate to="/login" />} />
        <Route path="/browse-sessions" element={user ? <BrowseSessions /> : <Navigate to="/login" />} /> <Route path="/profile" element={user ? <PlaceholderPage title="Profile" /> : <Navigate to="/login" />} />
        <Route path="/session/:id" element={user ? <PlaceholderPage title="Session Details" /> : <Navigate to="/login" />} />
        <Route path="/find-players" element={user ? <FindPlayers /> : <Navigate to="/login" />} />
        <Route path="/marketplace" element={user ? <Marketplace /> : <Navigate to="/login" />} />
      </Routes>
    </BrowserRouter>
  )
}

export default App
